#include <bits/stdc++.h>
using namespace std;
int n,a[14],ans;

bool check(int x,int y){
	for(int i=1;i<x;i++)
		if(a[i]==y || x-y==i-a[i] || x+y==i+a[i])
			return false;
	return true;
}

void dfs(int x){
	if(x>n){
		++ans;
		if(ans<=3){
			for(int i=1;i<=n;i++)
				cout<<a[i]<<' ';
			cout<<endl;
		}
	}
	else
		for(int i=1;i<=n;i++)
			if(check(x,i)){
				a[x]=i;
				dfs(x+1);
			}
} 
int main(){
	cin>>n;
	dfs(1);
	cout<<ans;
	return 0;
}
